import React, { useState, useEffect } from 'react';
import { Routes, Route, NavLink, Navigate, useNavigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import { ProjectProvider, useProjects } from './context/ProjectContext';

import Login from './components/auth/Login';
import Registration from './components/auth/Registration'; // Import the Registration component
import Users from './components/users/Users';
import ProjectList from './components/projects/ProjectList';
import ProjectView from './components/projects/ProjectView';
import KanbanBoard from './components/boards/KanbanBoard';
import Backlog from './components/backlog/Backlog';
import IssueDetails from './components/issues/IssueDetails';
import IssueCreate from './components/issues/IssueCreate';
import Assets from './components/assets/Assets';
import Timeline from './components/timeline/Timeline';
import ForYou from './components/dashboard/ForYou';
import Notifications from './components/notifications/Notifications';
import { FiMenu } from 'react-icons/fi';

// Component to handle the initial redirect
function InitialNavigation() {
  const navigate = useNavigate();

  useEffect(() => {
    const hasVisitedBefore = localStorage.getItem('hasVisitedFlowTrack');
    if (!hasVisitedBefore) {
      localStorage.setItem('hasVisitedFlowTrack', 'true');
      navigate("/register", { replace: true });
    } else {
      navigate("/login", { replace: true });
    }
  }, [navigate]);

  // Render nothing or a loading spinner while redirecting
  return (
    <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh', fontSize: '24px', color: '#666' }}>
      Loading...
    </div>
  );
}

// PrivateRoute: Only allows authenticated users
function PrivateRoute({ children }) {
  const { user, loading } = useAuth(); // Assume useAuth provides a loading state
  if (loading) {
    return (
      <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh', fontSize: '24px', color: '#666' }}>
        Loading user...
      </div>
    );
  }
  return user ? children : <Navigate to="/login" replace />;
}

export default function App() {
  return (
    <AuthProvider>
      <ProjectProvider>
        <Routes>
          {/*
            The root path will first check for authentication/visited status.
            If not authenticated or not visited, it will redirect to /register or /login.
            If authenticated, it will redirect to /for-you.
          */}
          <Route path="/" element={<AuthAndVisitedRedirect />} />

          {/* Login page */}
          <Route path="/login" element={<Login />} />
          {/* Registration page */}
          <Route path="/register" element={<Registration />} />

          {/* All other routes are private */}
          <Route path="/*" element={
            <PrivateRoute>
              <Layout />
            </PrivateRoute>
          } />
        </Routes>
      </ProjectProvider>
    </AuthProvider>
  );
}

// A new component to handle the complex initial redirect logic
function AuthAndVisitedRedirect() {
  const { user, loading } = useAuth();
  const navigate = useNavigate();
  const [initialCheckComplete, setInitialCheckComplete] = useState(false);

  useEffect(() => {
    if (!loading) { // Wait until auth context has finished loading the user
      const hasVisitedBefore = localStorage.getItem('hasVisitedFlowTrack');

      if (user) {
        // User is logged in, redirect to dashboard
        navigate("/for-you", { replace: true });
      } else {
        // User is not logged in
        if (!hasVisitedBefore) {
          // First visit, redirect to registration
          localStorage.setItem('hasVisitedFlowTrack', 'true');
          navigate("/register", { replace: true });
        } else {
          // Not first visit, redirect to login
          navigate("/login", { replace: true });
        }
      }
      setInitialCheckComplete(true);
    }
  }, [user, loading, navigate]);

  if (!initialCheckComplete || loading) {
    return (
      <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh', fontSize: '24px', color: '#666' }}>
        Loading...
      </div>
    );
  }

  // Should ideally never reach here if the logic above is sound,
  // but as a fallback, we can redirect to login.
  return <Navigate to="/login" replace />;
}


function Layout() {
  const { user, logout } = useAuth();
  // Ensure projects has a default empty array to avoid issues if context isn't ready
  const { projects = [] } = useProjects();

  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [currentProjectName, setCurrentProjectName] = useState(null);

  useEffect(() => {
    if (projects && projects.length > 0) {
      setCurrentProjectName(projects[0].name);
    } else {
      setCurrentProjectName(null);
    }
  }, [projects]);

  const toggleSidebar = () => setSidebarOpen(prev => !prev);

  const sidebarStyle = {
    width: sidebarOpen ? '240px' : '70px',
    transition: 'width 0.3s ease',
    backgroundColor: '#459cf9ff',
    color: '#ffffff',
    height: '100vh',
    padding: '16px 12px',
    boxSizing: 'border-box',
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'space-between',
    boxShadow: '2px 0 8px rgba(0,0,0,0.1)',
    position: 'fixed',
    left: 0,
    top: 0,
    zIndex: 1000
  };

  const navLinkBaseStyle = { // Base style for NavLink
    display: 'flex',
    alignItems: 'center',
    padding: '12px 16px',
    color: '#ffffff',
    textDecoration: 'none',
    fontSize: '15px',
    margin: '4px 0',
    borderRadius: '8px',
    transition: 'all 0.2s ease',
    fontWeight: '500',
    gap: '12px'
  };

  const navLinkActiveStyle = { // Style for active NavLink
    backgroundColor: '#ffffff',
    color: '#1f2937'
  };

  const contentStyle = {
    flex: 1,
    padding: '24px',
    backgroundColor: '#f9fafb',
    height: '100vh',
    overflowY: 'auto',
    marginLeft: sidebarOpen ? '240px' : '70px',
    transition: 'margin-left 0.3s ease'
  };

  const topbarStyle = {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    backgroundColor: '#ffffff',
    padding: '16px 24px',
    borderBottom: '1px solid #e5e7eb',
    boxShadow: '0 1px 4px rgba(0,0,0,0.05)',
    margin: '-24px -24px 24px -24px'
  };

  const appShellStyle = {
    display: 'flex',
    fontFamily: 'Segoe UI, Roboto, sans-serif',
    fontSize: '14px',
    color: '#111827',
    minHeight: '100vh'
  };

  const menuButtonStyle = {
    background: 'none',
    border: 'none',
    color: '#ffffff',
    cursor: 'pointer',
    padding: '8px',
    borderRadius: '6px',
    transition: 'background-color 0.2s ease'
  };

  const userInfoStyle = {
    fontSize: '14px',
    lineHeight: '1.4',
    padding: '16px',
    backgroundColor: '#ffffff',
    borderRadius: '8px',
    marginTop: '12px',
    border: '1px solid #e5e7eb',
    color: '#374151'
  };

  const btnLinkStyle = {
    background: 'none',
    border: 'none',
    color: '#60a5fa',
    cursor: 'pointer',
    padding: '0',
    marginTop: '8px',
    fontSize: '13px',
    textDecoration: 'underline'
  };

  const logoStyle = {
    fontSize: '20px',
    fontWeight: 'bold',
    color: '#ffffff',
    marginBottom: '24px',
    padding: '0 8px'
  };

  const navSectionStyle = {
    marginBottom: '24px'
  };

  const navItems = [
    { path: '/for-you', label: 'For You', icon: '⭐' },
    { path: '/projects', label: 'Projects', icon: '📁' },
    // Ensure currentProjectName is defined before using it in the path
    { path: currentProjectName ? `/kanban/${currentProjectName}` : '/kanban/default', label: 'Boards', icon: '📊' },
    { path: '/assets', label: 'Assets', icon: '🖼️' },
    { path: '/timeline', label: 'Timeline', icon: '📅' },
    { path: '/users', label: 'Users', icon: '👥' },
  ];

  return (
    <div style={appShellStyle} role="application" aria-label="Ticketing application">
      <aside style={sidebarStyle} aria-label="Sidebar navigation">
        <div style={navSectionStyle}>
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '8px' }}>
            {sidebarOpen && <div style={logoStyle}>FLOW TRACK</div>}
            <button
              style={menuButtonStyle}
              onClick={toggleSidebar}
              aria-label="Toggle sidebar"
              onMouseOver={(e) => e.target.style.backgroundColor = 'rgba(255,255,255,0.2)'} // More subtle hover
              onMouseOut={(e) => e.target.style.backgroundColor = 'transparent'}
            >
              <FiMenu size={20} />
            </button>
          </div>

          <nav role="navigation" aria-label="Main">
            {navItems.map(({ path, label, icon }) => (
              <NavLink
                key={path}
                to={path}
                style={({ isActive }) =>
                  isActive
                    ? { ...navLinkBaseStyle, ...navLinkActiveStyle }
                    : navLinkBaseStyle
                }
                end
              >
                <span style={{ fontSize: '18px' }}>{icon}</span>
                {sidebarOpen && <span>{label}</span>}
              </NavLink>
            ))}
          </nav>
        </div>

        <div style={navSectionStyle}>
          {user ? (
            <div style={userInfoStyle} aria-label="User Profile">
              {sidebarOpen ? (
                <>
                  <div style={{ fontWeight: '600', marginBottom: '4px' }}>{user.name || 'User'}</div>
                  <div style={{ color: '#6b7280', fontSize: '13px', marginBottom: '8px' }}>{user.email || 'user@example.com'}</div>
                  <button
                    style={{ ...btnLinkStyle, color: '#4f46e5' }}
                    onClick={logout}
                    onMouseOver={(e) => e.target.style.color = '#6366f1'}
                    onMouseOut={(e) => e.target.style.color = '#4f46e5'}
                  >
                    Sign out
                  </button>
                </>
              ) : (
                <div style={{ textAlign: 'center', color: '#374151' }}>👤</div>
              )}
            </div>
          ) : (
            <NavLink
              to="/login"
              style={({ isActive }) =>
                isActive
                  ? { ...navLinkBaseStyle, ...navLinkActiveStyle }
                  : navLinkBaseStyle
              }
            >
              <span style={{ fontSize: '18px' }}>🔐</span>
              {sidebarOpen && <span>Sign in</span>}
            </NavLink>
          )}
        </div>
      </aside>

      <div style={contentStyle}>
        <header style={topbarStyle} role="banner">
          <div>
            <h1 style={{ margin: 0, fontSize: '24px', fontWeight: '600', color: '#111827' }}>Flow Track</h1>
          </div>
          <div style={{ fontSize: '14px', color: '#6b7280' }}>Accessible demo • keyboard friendly</div>
        </header>

        <main id="main" tabIndex="-1" role="main" style={{ maxWidth: '1200px', margin: '0 auto' }}>
          <Routes>
            <Route path="/projects" element={<ProjectList />} />
            <Route path="/projects/:id" element={<ProjectView />} />
            <Route path="/kanban/:name" element={<KanbanBoard />} />
            <Route path="/backlog/:id" element={<Backlog />} />
            <Route path="/issues/new" element={<IssueCreate />} />
            <Route path="/issues/:id" element={<IssueDetails />} />
            <Route path="/assets" element={<Assets />} />
            <Route path="/timeline" element={<Timeline />} />
            <Route path="/users" element={<Users />} />
            <Route path="/notifications" element={<Notifications />} />
            <Route path="/for-you" element={<ForYou />} />
            {/* Fallback for any unmatched private route, redirect to /for-you */}
            <Route path="*" element={<Navigate to="/for-you" replace />} />
          </Routes>
        </main>
      </div>
    </div>
  );
}
